code = """import json
# Load review business_refs
reviews = var_call_Dj9V76ytJrYQWKXy8W0i0hua
# Build set of businessids corresponding to reviews
business_ids = set()
for r in reviews:
    br = r.get('business_ref')
    if br and br.startswith('businessref_'):
        business_ids.add('businessid_' + br.split('_',1)[1])

# Collect business records from available query results
business_records = []
possible_vars = ['var_call_XN6O4VfduxYf8D4MeX7DNEP1','var_call_f0Wv4DsoBRCLdD3cHEH8JuYY','var_call_bus4bXbRwWBz4degIYRemTQk','var_call_wFuQ6bzCk5hnWnHWFglwf1r4','var_call_0iNG1wclB94S63rnG72zX9mz','var_call_XgyLi0Wq21LyjHQ5tA3LsxpE','var_call_7L2OA3SaFvun4w9DXXXytzn6']
for var in possible_vars:
    try:
        recs = globals()[var]
        if isinstance(recs, list):
            business_records.extend(recs)
    except Exception:
        pass

# Build mapping
biz_attr = {}
for rec in business_records:
    bid = rec.get('business_id')
    attr = rec.get('attributes')
    biz_attr[bid] = attr

# Function to check parking
def has_parking(attr):
    if attr is None:
        return False
    # attr could be string 'None'
    if isinstance(attr, str):
        # sometimes entire attributes is a string 'None'
        if attr == 'None':
            return False
        # Otherwise it's unexpected string; we can't parse reliably
    # Check BikeParking
    bp = None
    if isinstance(attr, dict):
        bp = attr.get('BikeParking')
        bpark = attr.get('BusinessParking')
    else:
        # attr is likely dict-like but values maybe strings; handle both
        bp = attr.get('BikeParking') if isinstance(attr, dict) or isinstance(attr, (dict,)) else None
        bpark = attr.get('BusinessParking') if isinstance(attr, dict) or isinstance(attr, (dict,)) else None
        # But in our data attr is dict already (as parsed by the tool)
        # However sometimes values inside dict are strings representing dicts
    # Check BikeParking value
    if bp is not None:
        # bp might be string 'True'/'False' or boolean
        if isinstance(bp, str):
            if bp.strip().lower() == "true":
                return True
        elif isinstance(bp, bool):
            if bp:
                return True
    # Check BusinessParking
    if bpark is not None:
        # bpark might be a string like "{'garage': False, 'street': True, ...}"
        if isinstance(bpark, str):
            if bpark == 'None':
                return False
            # If any True in string, consider parking offered
            if 'True' in bpark:
                return True
            # Also sometimes 'true' lower
            if 'true' in bpark:
                return True
            return False
        elif isinstance(bpark, dict):
            # if any value True
            for v in bpark.values():
                if v is True:
                    return True
            return False
    return False

# Count
count = 0
found_biz = []
for bid in business_ids:
    attr = biz_attr.get(bid)
    if has_parking(attr):
        count += 1
        found_biz.append(bid)

# Prepare result
result = {"count": count, "businesses": sorted(list(found_biz))}
print("__RESULT__:")
print(json.dumps(result))"""

